import assert from 'assert';
import { ensureNoDisposablesAreLeakedInTestSuite } from '../../../../../base/test/common/utils.js';
import { NamedRegionRangeProvider, NamedRegion } from '../../browser/namedRegionProvider.js';
import { createTextModel } from '../../../../test/common/testTextModel.js';

interface RangesLimitReporter {
	limit: number;
	update(computed: number, limited: number | false): void;
}

class TestRangesLimitReporter implements RangesLimitReporter {
	limit = 5000;
	update(computed: number, limited: number | false): void {
		// no-op for testing
	}
}

suite('Named Region Provider', () => {
	ensureNoDisposablesAreLeakedInTestSuite();

	test('Detects simple named region', async () => {
		const lines = [
			'// #region MySection',
			'const a = 1;',
			'// #endregion'
		];
		const model = createTextModel(lines.join('\n'));
		const provider = new NamedRegionRangeProvider(model, new TestRangesLimitReporter());
		const result = await provider.compute({
			isCancellationRequested: false,
			onCancellationRequested: () => ({ dispose: () => { } })
		});

		assert.strictEqual(result !== null, true, 'Should return a FoldingRegions');
		assert.strictEqual(result?.length, 1, 'Should have 1 region');
		assert.strictEqual(result?.getStartLineNumber(0), 1, 'Start line should be 1');
		assert.strictEqual(result?.getEndLineNumber(0), 3, 'End line should be 3');

		const namedRegions = provider.getNamedRegions();
		assert.strictEqual(namedRegions.length, 1, 'Should have 1 named region');
		assert.strictEqual(namedRegions[0].name, 'MySection', 'Region name should be MySection');
		assert.strictEqual(namedRegions[0].startLineNumber, 1, 'Start line number should be 1');
		assert.strictEqual(namedRegions[0].endLineNumber, 3, 'End line number should be 3');

		model.dispose();
	});

	test('Detects multiple named regions', async () => {
		const lines = [
			'// #region FirstSection',
			'const a = 1;',
			'// #endregion',
			'',
			'// #region SecondSection',
			'const b = 2;',
			'// #endregion'
		];
		const model = createTextModel(lines.join('\n'));
		const provider = new NamedRegionRangeProvider(model, new TestRangesLimitReporter());
		const result = await provider.compute({
			isCancellationRequested: false,
			onCancellationRequested: () => ({ dispose: () => { } })
		});

		assert.strictEqual(result !== null, true, 'Should return a FoldingRegions');
		assert.strictEqual(result?.length, 2, 'Should have 2 regions');

		const namedRegions = provider.getNamedRegions();
		assert.strictEqual(namedRegions.length, 2, 'Should have 2 named regions');
		assert.strictEqual(namedRegions[0].name, 'FirstSection', 'First region name should be FirstSection');
		assert.strictEqual(namedRegions[1].name, 'SecondSection', 'Second region name should be SecondSection');
	});

	test('Detects nested named regions', async () => {
		const lines = [
			'// #region OuterSection',
			'  // #region InnerSection',
			'  const a = 1;',
			'  // #endregion',
			'// #endregion'
		];
		const model = createTextModel(lines.join('\n'));
		const provider = new NamedRegionRangeProvider(model, new TestRangesLimitReporter());
		const result = await provider.compute({
			isCancellationRequested: false,
			onCancellationRequested: () => ({ dispose: () => { } })
		});

		assert.strictEqual(result !== null, true, 'Should return a FoldingRegions');
		assert.strictEqual(result?.length, 2, 'Should have 2 regions');

		const namedRegions = provider.getNamedRegions();
		assert.strictEqual(namedRegions.length, 2, 'Should have 2 named regions');
		assert.strictEqual(namedRegions[0].name, 'OuterSection', 'First region name');
		assert.strictEqual(namedRegions[0].startLineNumber, 1, 'Outer region starts at line 1');
		assert.strictEqual(namedRegions[0].endLineNumber, 5, 'Outer region ends at line 5');
		assert.strictEqual(namedRegions[1].name, 'InnerSection', 'Second region name');
		assert.strictEqual(namedRegions[1].startLineNumber, 2, 'Inner region starts at line 2');
		assert.strictEqual(namedRegions[1].endLineNumber, 4, 'Inner region ends at line 4');
	});

	test('Handles region names with spaces', async () => {
		const lines = [
			'// #region My Multi Word Section',
			'const a = 1;',
			'// #endregion'
		];
		const model = createTextModel(lines.join('\n'));
		const provider = new NamedRegionRangeProvider(model, new TestRangesLimitReporter());
		const result = await provider.compute({
			isCancellationRequested: false,
			onCancellationRequested: () => ({ dispose: () => { } })
		});

		const namedRegions = provider.getNamedRegions();
		assert.strictEqual(namedRegions[0].name, 'My Multi Word Section', 'Region name with spaces');
	});

	test('Returns null for empty file', async () => {
		const model = createTextModel('');
		const provider = new NamedRegionRangeProvider(model, new TestRangesLimitReporter());
		const result = await provider.compute({
			isCancellationRequested: false,
			onCancellationRequested: () => ({ dispose: () => { } })
		});

		assert.strictEqual(result, null, 'Should return null for empty file');
	});

	test('Returns null for file with no named regions', async () => {
		const lines = [
			'const a = 1;',
			'const b = 2;'
		];
		const model = createTextModel(lines.join('\n'));
		const provider = new NamedRegionRangeProvider(model, new TestRangesLimitReporter());
		const result = await provider.compute({
			isCancellationRequested: false,
			onCancellationRequested: () => ({ dispose: () => { } })
		});

		assert.strictEqual(result, null, 'Should return null when no regions found');
	});

	test('Supports block comment style regions', async () => {
		const lines = [
			'/* #region BlockSection */',
			'const a = 1;',
			'/* #endregion */'
		];
		const model = createTextModel(lines.join('\n'));
		const provider = new NamedRegionRangeProvider(model, new TestRangesLimitReporter());
		const result = await provider.compute({
			isCancellationRequested: false,
			onCancellationRequested: () => ({ dispose: () => { } })
		});

		const namedRegions = provider.getNamedRegions();
		assert.strictEqual(namedRegions[0].name, 'BlockSection', 'Should detect block comment regions');
	});

	test('Ignores unmatched endregion markers', async () => {
		const lines = [
			'// #region MySection',
			'const a = 1;',
			'// #endregion',
			'// #endregion'  // Extra unmatched endregion
		];
		const model = createTextModel(lines.join('\n'));
		const provider = new NamedRegionRangeProvider(model, new TestRangesLimitReporter());
		const result = await provider.compute({
			isCancellationRequested: false,
			onCancellationRequested: () => ({ dispose: () => { } })
		});

		const namedRegions = provider.getNamedRegions();
		assert.strictEqual(namedRegions.length, 1, 'Should have 1 region, ignoring unmatched endregion');
	});
});

